    report_id,
    report_title,
    author_name, 
    publisher, 
    read_date, 
    report_text 

) VALUES (
    #{report_id}
    #{report_title},
    #{author_name},
    #{publisher},
    #{read_date},
    #{report_text}
    where member_idx=#{member_idx}


)

mapper.select:
SELECT br.report_id, br.member_idx, br.report_title, br.author_name, br.publisher, br.read_date, br.report_text, br.report_regdate
FROM book_report br
WHERE br.member_idx = #{member_idx};
